-- 006_finance.sql — Módulo Finanzas/Contabilidad (P&L) + budget 2026 (QuickBooks)
-- Plan de cuentas jerárquico + presupuesto (proyección) + reales. Idempotente.

create table if not exists public.finance_accounts (
  id text primary key, code text, name text not null,
  parent_id text references public.finance_accounts(id),
  section text, sort int default 0, is_leaf boolean default true );
create table if not exists public.finance_budget (
  account_id text references public.finance_accounts(id) on delete cascade,
  year int not null, month int not null, amount numeric not null default 0,
  primary key (account_id, year, month) );
create table if not exists public.finance_actuals (
  id uuid primary key default gen_random_uuid(),
  account_id text references public.finance_accounts(id) on delete cascade,
  year int not null, month int not null, amount numeric not null default 0,
  note text, source text default 'manual', created_at timestamptz default now() );
create index if not exists idx_fin_actuals_acc on public.finance_actuals(account_id, year, month);
alter table public.finance_accounts enable row level security;
alter table public.finance_budget enable row level security;
alter table public.finance_actuals enable row level security;
drop policy if exists fin_acc_r on public.finance_accounts;
create policy fin_acc_r on public.finance_accounts for select using (get_my_role() in ('owner','manager','contador'));
drop policy if exists fin_acc_w on public.finance_accounts;
create policy fin_acc_w on public.finance_accounts for all using (get_my_role() in ('owner','manager'));
drop policy if exists fin_bud_r on public.finance_budget;
create policy fin_bud_r on public.finance_budget for select using (get_my_role() in ('owner','manager','contador'));
drop policy if exists fin_bud_w on public.finance_budget;
create policy fin_bud_w on public.finance_budget for all using (get_my_role() in ('owner','manager'));
drop policy if exists fin_act_r on public.finance_actuals;
create policy fin_act_r on public.finance_actuals for select using (get_my_role() in ('owner','manager','contador'));
drop policy if exists fin_act_w on public.finance_actuals;
create policy fin_act_w on public.finance_actuals for all using (get_my_role() in ('owner','manager'));

